export default {
    namespaced: true,
    state: {
        header: [],
        sider: [],
        headerName: '',
        activePath: '',
        openNames: [],
        menuSider: [],
        menuBadge: []
    },
    mutations: {
        setSider (state, menu) { state.sider = menu; },
        setHeader (state, menu) { state.header = menu; },
        setHeaderName (state, name) { state.headerName = name; },
        setActivePath (state, path) { state.activePath = path; },
        setOpenNames (state, names) { state.openNames = names; }
    }
};
