import Vue from 'vue';
import VueRouter from 'vue-router';
import screenRoutes from './screen-routes';

Vue.use(VueRouter);

const routes = [
  {
    path: '/',
    redirect: '/screen-select'
  },
  ...screenRoutes
];

const router = new VueRouter({
  mode: 'hash',
  base: '/',
  routes
});

export default router;
