import util from '@/libs/util';
import { cloneDeep } from 'lodash';

function pathInit ({
    dbName = 'database',
    path = '',
    user = true,
    defaultValue = ''
}) {
    const uuid = util.cookies.get('uuid') || 'ghost-uuid';
    const currentPath = `${dbName}.${user ? `user.${uuid}` : 'public'}${path ? `.${path}` : ''}`;
    const value = util.db.get(currentPath).value();

    if (value === undefined) {
        util.db.set(currentPath, defaultValue).write();
    }
    return currentPath;
}

export { pathInit };

export default {
    namespaced: true,
    actions: {
        set (context, { dbName = 'database', path = '', value = '', user = false }) {
            util.db.set(pathInit({ dbName, path, user }), value).write();
        },
        get (context, { dbName = 'database', path = '', defaultValue = '', user = false }) {
            return new Promise(resolve => {
                resolve(cloneDeep(util.db.get(pathInit({ dbName, path, user, defaultValue })).value()));
            });
        }
    }
};
