import Setting from '@/setting';

export default {
    namespaced: true,
    state: {
        pool: [],
        opened: Setting.page.opened,
        current: '',
        keepAlive: []
    },
    actions: {
        openedLoad ({ state }) {
            return new Promise(resolve => { resolve(); });
        }
    },
    mutations: {
        currentSet (state, fullPath) { state.current = fullPath; }
    }
};
