import Setting from '@/setting';

export default {
    namespaced: true,
    state: {
        ...Setting.layout,
        isMobile: false,
        isTablet: false,
        isDesktop: true,
        isFullscreen: false
    },
    mutations: {
        setDevice (state, type) {
            state.isMobile = false;
            state.isTablet = false;
            state.isDesktop = false;
            state[`is${type}`] = true;
        },
        updateMenuCollapse (state, collapse) {
            state.menuCollapse = collapse;
        }
    }
};
